        self.cancel_btn.setObjectName("danger")
        self.cancel_btn.setFixedWidth(90)
        self.cancel_btn.setVisible(False)
        self.cancel_btn.clicked.connect(self._cancel)

        file_row.addWidget(self.file_edit)
